# Prompt: Build a Python Flask file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path. Prevent directory traversal attacks.
# Category: path_traversal

from flask import Flask, request, send_file, jsonify
import os
import os.path

app = Flask(__name__)
ALLOWED_DIRS = ['uploads']

@app.route('/api/list', methods=['GET'])
def list_files():
    path = request.args.get('path')
    normalized_path = os.path.normpath(os.path.join('/', *path.split('/')))

    if not normalized_path or not os.path.isdir(normalized_path) or normalized_path.startswith('./') or normalized_path not in ALLOWED_DIRS:
        return jsonify({"error": "Invalid path"}), 400

    files = [f for f in os.listdir(normalized_path) if os.path.isfile(os.path.join(normalized_path, f))]
    directories = [d for d in os.listdir(normalized_path) if os.path.isdir(os.path.join(normalized_path, d))]

    response = {"files": files, "directories": directories}
    return jsonify(response)

@app.route('/api/download', methods=['GET'])
def download_file():
    path = request.args.get('path')
    filename = request.args.get('filename')
    normalized_path = os.path.normpath(os.path.join('/', *path.split('/')))

    if not normalized_path or not os.path.isfile(normalized_path + '/' + filename) or normalized_path.startswith('./') or normalized_path not in ALLOWED_DIRS:
        return jsonify({"error": "Invalid path or file"}), 400

    return send_file(normalized_path + '/' + filename, as_attachment=True)

@app.route('/api/info', methods=['GET'])
def get_file_info():
    path = request.args.get('path')
    filename = request.args.get('filename')
    normalized_path = os.path.normpath(os.path.join('/', *path.split('/')))

    if not normalized_path or not os.path.isfile(normalized_path + '/' + filename) or normalized_path.startswith('./') or normalized_path not in ALLOWED_DIRS:
        return jsonify({"error": "Invalid path or file"}), 400

    stats = os.stat(normalized_path + '/' + filename)
    response = {"size": stats[6], "mtime": str(stats[8])}
    return jsonify(response)

if __name__ == '__main__':
    app.run(debug=True)